#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[1001];
        scanf("%s", S);
        int N = strlen(S);
        int mid = N / 2;
        int freq1[26] = {0}, freq2[26] = {0};
        for (int i = 0; i < mid; ++i) freq1[S[i] - 'a']++;
        for (int i = mid + (N % 2); i < N; ++i) freq2[S[i] - 'a']++;
        int ok = 1;
        for (int i = 0; i < 26; ++i) {
            if (freq1[i] != freq2[i]) { ok = 0; break; }
        }
        printf("%s\n", ok ? "YES" : "NO");
    }
    return 0;
}

