const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(input[idx++].trim(), 10);
let results = [];
for (let t = 0; t < T; ++t) {
    const S = input[idx++].trim();
    const N = S.length;
    const mid = Math.floor(N / 2);
    const freq1 = new Array(26).fill(0);
    const freq2 = new Array(26).fill(0);
    for (let i = 0; i < mid; ++i) {
        freq1[S.charCodeAt(i) - 97]++;
    }
    for (let i = mid + (N % 2); i < N; ++i) {
        freq2[S.charCodeAt(i) - 97]++;
    }
    let ok = true;
    for (let i = 0; i < 26; ++i) {
        if (freq1[i] !== freq2[i]) { ok = false; break; }
    }
    results.push(ok ? 'YES' : 'NO');
}
console.log(results.join('\n'));
